{"file_path":"/project/ktlint-ruleset-standard/src/test/kotlin/com/pinterest/ktlint/ruleset/standard/rules/NoWildcardImportsRuleKtlintOfficialCodeStyleTest.kt","content":"package com.pinterest.ktlint.ruleset.standard.rules

import com.pinterest.ktlint.rule.engine.core.api.editorconfig.CODE_STYLE_PROPERTY
import com.pinterest.ktlint.rule.engine.core.api.editorconfig.CodeStyleValue.ktlint_official
import com.pinterest.ktlint.ruleset.standard.rules.NoWildcardImportsRule.Companion.IJ_KOTLIN_PACKAGES_TO_USE_IMPORT_ON_DEMAND
import com.pinterest.ktlint.test.KtLintAssertThat.Companion.assertThatRule
import com.pinterest.ktlint.test.LintViolation
import org.junit.jupiter.api.Test

class NoWildcardImportsRuleKtlintOfficialCodeStyleTest {
    private val noWildcardImportsRuleAssertThat = assertThatRule { NoWildcardImportsRule() }

    @Test
    fun `Given ktlint_official code style and packagesToUseImportOnDemandProperty is not set then IntelliJ default wildcard imports are violations`() {
        val code =
            """
            import java.util.*
            import kotlinx.android.synthetic.main.layout_name.*
            """.trimIndent()

        noWildcardImportsRuleAssertThat(code)
            .withEditorConfigOverride(CODE_STYLE_PROPERTY to ktlint_official)
            .hasLintViolationsWithoutAutoCorrect(
                LintViolation(1, 1, "Wildcard import"),
                LintViolation(2, 1, "Wildcard import"),
            )
    }

    @Test
    fun `Given ktlint_official code style and packagesToUseImportOnDemandProperty explicitly allows java util then java util wildcard import is not a violation`() {
        val code =
            """
            import java.util.*
            """.trimIndent()

        noWildcardImportsRuleAssertThat(code)
            .withEditorConfigOverride(
                CODE_STYLE_PROPERTY to ktlint_official,
                IJ_KOTLIN_PACKAGES_TO_USE_IMPORT_ON_DEMAND to "java.util.*",
            )
            .hasNoLintViolations()
    }
}
"}

